drop extension if exists "pg_net";


  create table "public"."marketplace_author_profiles" (
    "user_id" uuid not null,
    "display_name" text not null default 'Discord user'::text,
    "avatar_url" text,
    "updated_at" timestamp with time zone not null default now()
      );


alter table "public"."marketplace_author_profiles" enable row level security;


  create table "public"."marketplace_download_events" (
    "id" bigint generated by default as identity not null,
    "user_id" uuid not null,
    "preset_id" uuid not null,
    "created_at" timestamp with time zone not null default now()
      );


