  create table "public"."marketplace_like_events" (
    "id" bigint generated by default as identity not null,
    "user_id" uuid not null,
    "preset_id" uuid not null,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."marketplace_like_events" enable row level security;


  create table "public"."marketplace_presets" (
    "id" uuid not null default gen_random_uuid(),
    "created_at" timestamp with time zone not null default now(),
    "slug" text not null,
    "name" text not null,
    "author_name" text not null,
    "description" text not null default ''::text,
    "tags" text[] not null default '{}'::text[],
    "game_version" text,
    "pathmind_version" text,
    "likes_count" integer not null default 0,
    "downloads_count" integer not null default 0,
    "file_path" text not null,
    "published" boolean not null default true,
    "updated_at" timestamp with time zone not null default now(),
    "author_user_id" uuid,
    "storage_bucket" text not null default 'graphs'::text,
    "author_avatar_url" text
      );


alter table "public"."marketplace_presets" enable row level security;


  create table "public"."marketplace_publish_events" (
    "id" bigint generated by default as identity not null,
    "user_id" uuid not null,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."marketplace_publish_events" enable row level security;


  create table "public"."marketplace_roles" (
    "user_id" uuid not null,
    "role" text not null,
    "created_at" timestamp with time zone not null default now(),
    "updated_at" timestamp with time zone not null default now()
      );


alter table "public"."marketplace_roles" enable row level security;


  create table "public"."preset_likes" (
    "preset_id" uuid not null,
    "user_id" uuid not null,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."preset_likes" enable row level security;

