    if coalesce(trim(preset_storage_bucket), '') = '' then
        raise exception 'Preset storage bucket is required.'
            using errcode = 'P0001';
    end if;

    select count(*)
    into recent_publish_count
    from public.marketplace_publish_events
    where user_id = auth.uid()
      and created_at >= now() - interval '10 minutes';

    if recent_publish_count >= 5 then
        raise exception 'Publish rate limit exceeded. Try again in a few minutes.'
            using errcode = 'P0001';
    end if;

    insert into public.marketplace_publish_events (user_id)
    values (auth.uid());

    select coalesce(array_agg(tag), array[]::text[])
    into normalized_tags
    from (
        select distinct left(trim(tag), 32) as tag
        from unnest(coalesce(preset_tags, array[]::text[])) as tag
        where coalesce(trim(tag), '') <> ''
        limit 12
    ) normalized;

    insert into public.marketplace_presets (
        slug,
        name,
        author_name,
        description,
        tags,
        game_version,
        pathmind_version,
        storage_bucket,
        file_path,
        published,
        author_user_id
    )
    values (
        trim(preset_slug),
        left(trim(preset_name), 64),
        coalesce(nullif(trim(preset_author_name), ''), 'Discord user'),
        left(coalesce(trim(preset_description), ''), 180),
        normalized_tags,
        nullif(trim(preset_game_version), ''),
        nullif(trim(preset_pathmind_version), ''),
        trim(preset_storage_bucket),
        trim(preset_file_path),
        coalesce(preset_published, true),
        auth.uid()
    )
    returning *
    into inserted_row;

    return inserted_row;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
    new.updated_at = now();
    return new;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_marketplace_author_profile(p_display_name text, p_avatar_url text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
    if auth.uid() is null then
        raise exception 'Not authenticated';
    end if;

    insert into public.marketplace_author_profiles (user_id, display_name, avatar_url, updated_at)
    values (
        auth.uid(),
        coalesce(nullif(trim(p_display_name), ''), 'Discord user'),
        nullif(trim(p_avatar_url), ''),
        now()
    )
    on conflict (user_id) do update
    set display_name = excluded.display_name,
        avatar_url = excluded.avatar_url,
        updated_at = now();

    update public.marketplace_presets
    set author_name = coalesce(nullif(trim(p_display_name), ''), author_name),
        author_avatar_url = nullif(trim(p_avatar_url), ''),
        updated_at = now()
    where author_user_id = auth.uid();
end;
$function$
;

CREATE OR REPLACE FUNCTION public.sync_preset_likes_count()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
    update public.marketplace_presets
    set likes_count = (
        select count(*)
        from public.preset_likes pl
        where pl.preset_id = coalesce(new.preset_id, old.preset_id)
    ),
    updated_at = now()
    where id = coalesce(new.preset_id, old.preset_id);

    return coalesce(new, old);
end;
$function$
;

CREATE OR REPLACE FUNCTION public.toggle_marketplace_preset_like(target_preset_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
    recent_like_count integer;
    liked_now boolean;
    updated_likes_count integer;
begin
    if auth.uid() is null then
        raise exception 'Authentication required.'
            using errcode = '42501';
    end if;

    if not exists (
        select 1
        from public.marketplace_presets
        where id = target_preset_id
          and published = true
    ) then
        raise exception 'Preset not found.'
            using errcode = 'P0001';
    end if;

    select count(*)
    into recent_like_count
    from public.marketplace_like_events
    where user_id = auth.uid()
      and preset_id = target_preset_id
      and created_at >= now() - interval '2500 milliseconds';

    if recent_like_count > 0 then
        raise exception 'Like rate limit exceeded. Try again in a moment.'
            using errcode = 'P0001';
    end if;

    insert into public.marketplace_like_events (user_id, preset_id)
    values (auth.uid(), target_preset_id);

    if exists (
        select 1
        from public.preset_likes
        where preset_id = target_preset_id
          and user_id = auth.uid()
    ) then
        delete from public.preset_likes
        where preset_id = target_preset_id
          and user_id = auth.uid();
        liked_now := false;
    else
        insert into public.preset_likes (preset_id, user_id)
        values (target_preset_id, auth.uid());
        liked_now := true;
    end if;

    select count(*)
    into updated_likes_count
    from public.preset_likes
    where preset_id = target_preset_id;

    update public.marketplace_presets
    set likes_count = updated_likes_count,
        updated_at = now()
    where id = target_preset_id;

    return jsonb_build_object(
        'liked', liked_now,
        'likes_count', updated_likes_count
    );
end;
$function$
;

CREATE OR REPLACE FUNCTION public.update_marketplace_preset_metadata(target_preset_id uuid, preset_name text, preset_description text, preset_tags text[], preset_game_version text, preset_pathmind_version text, preset_published boolean DEFAULT NULL::boolean, preset_storage_bucket text DEFAULT NULL::text, preset_file_path text DEFAULT NULL::text)
 RETURNS public.marketplace_presets
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
    updated_row public.marketplace_presets;
    normalized_tags text[];
begin
    if auth.uid() is null then
        raise exception 'Authentication required.'
            using errcode = '42501';
    end if;

    if coalesce(trim(preset_name), '') = '' then
        raise exception 'Preset name is required.'
            using errcode = 'P0001';
    end if;

    select coalesce(array_agg(tag), array[]::text[])
    into normalized_tags
    from (
        select distinct left(trim(tag), 32) as tag
        from unnest(coalesce(preset_tags, array[]::text[])) as tag
        where coalesce(trim(tag), '') <> ''
        limit 12
    ) normalized;

    update public.marketplace_presets
    set name = left(trim(preset_name), 64),
        description = left(coalesce(trim(preset_description), ''), 180),
        tags = normalized_tags,
        game_version = nullif(trim(preset_game_version), ''),
        pathmind_version = nullif(trim(preset_pathmind_version), ''),
        published = coalesce(preset_published, published),
        storage_bucket = coalesce(nullif(trim(preset_storage_bucket), ''), storage_bucket),
        file_path = coalesce(nullif(trim(preset_file_path), ''), file_path),
        updated_at = now()
    where id = target_preset_id
      and (
          author_user_id = auth.uid()
          or public.is_marketplace_moderator(auth.uid())
      )
    returning *
    into updated_row;

    if updated_row.id is null then
        raise exception 'Preset not found or not owned by current user.'
            using errcode = '42501';
    end if;

    return updated_row;
end;
$function$
;

