  create policy "Public can read marketplace author profiles"
  on "public"."marketplace_author_profiles"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "Users can manage own marketplace author profile"
  on "public"."marketplace_author_profiles"
  as permissive
  for all
  to authenticated
using ((auth.uid() = user_id))
with check ((auth.uid() = user_id));



  create policy "Marketplace moderators can read all presets"
  on "public"."marketplace_presets"
  as permissive
  for select
  to authenticated
using (public.is_marketplace_moderator(auth.uid()));



  create policy "Owners can read their marketplace presets"
  on "public"."marketplace_presets"
  as permissive
  for select
  to authenticated
using ((author_user_id = auth.uid()));



  create policy "Public can read published marketplace presets"
  on "public"."marketplace_presets"
  as permissive
  for select
  to anon, authenticated
using ((published = true));



  create policy "Public can read published presets"
  on "public"."marketplace_presets"
  as permissive
  for select
  to anon, authenticated
using ((published = true));



  create policy "authenticated users can delete own presets"
  on "public"."marketplace_presets"
  as permissive
  for delete
  to authenticated
using ((author_user_id = auth.uid()));



  create policy "authenticated users can insert own presets"
  on "public"."marketplace_presets"
  as permissive
  for insert
  to authenticated
with check ((author_user_id = auth.uid()));



  create policy "authenticated users can read own presets"
  on "public"."marketplace_presets"
  as permissive
  for select
  to authenticated
using (((published = true) OR (author_user_id = auth.uid())));



  create policy "authenticated users can update own presets"
  on "public"."marketplace_presets"
  as permissive
  for update
  to authenticated
using ((author_user_id = auth.uid()))
with check ((author_user_id = auth.uid()));



  create policy "published presets are publicly readable"
  on "public"."marketplace_presets"
  as permissive
  for select
  to public
using ((published = true));



  create policy "Marketplace admins manage roles"
  on "public"."marketplace_roles"
  as permissive
  for all
  to authenticated
using ((EXISTS ( SELECT 1
   FROM public.marketplace_roles actor
  WHERE ((actor.user_id = auth.uid()) AND (actor.role = 'admin'::text)))))
with check ((EXISTS ( SELECT 1
   FROM public.marketplace_roles actor
  WHERE ((actor.user_id = auth.uid()) AND (actor.role = 'admin'::text)))));



  create policy "Users can read own marketplace role"
  on "public"."marketplace_roles"
  as permissive
  for select
  to authenticated
using ((user_id = auth.uid()));



  create policy "Authenticated users can like presets"
  on "public"."preset_likes"
  as permissive
  for insert
  to authenticated
with check ((auth.uid() = user_id));



  create policy "Authenticated users can unlike their own likes"
  on "public"."preset_likes"
  as permissive
  for delete
  to authenticated
using ((auth.uid() = user_id));



  create policy "Public can read likes"
  on "public"."preset_likes"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "Users can delete their own preset likes"
  on "public"."preset_likes"
  as permissive
  for delete
  to authenticated
using ((user_id = auth.uid()));



  create policy "Users can insert their own preset likes"
  on "public"."preset_likes"
  as permissive
  for insert
  to authenticated
with check ((user_id = auth.uid()));



  create policy "Users can read their own preset likes"
  on "public"."preset_likes"
  as permissive
  for select
  to authenticated
using ((user_id = auth.uid()));


CREATE TRIGGER marketplace_presets_set_updated_at BEFORE UPDATE ON public.marketplace_presets FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

CREATE TRIGGER preset_likes_sync_count_delete AFTER DELETE ON public.preset_likes FOR EACH ROW EXECUTE FUNCTION public.sync_preset_likes_count();

CREATE TRIGGER preset_likes_sync_count_insert AFTER INSERT ON public.preset_likes FOR EACH ROW EXECUTE FUNCTION public.sync_preset_likes_count();


  create policy "Marketplace moderators can delete preset storage"
  on "storage"."objects"
  as permissive
  for delete
  to authenticated
using (((bucket_id = ANY (ARRAY['graphs'::text, 'private_graphs'::text])) AND public.is_marketplace_moderator(auth.uid())));



  create policy "Marketplace moderators can insert preset storage"
  on "storage"."objects"
  as permissive
  for insert
  to authenticated
with check (((bucket_id = ANY (ARRAY['graphs'::text, 'private_graphs'::text])) AND public.is_marketplace_moderator(auth.uid())));



