  for select
  to authenticated
using (((bucket_id = 'private_graphs'::text) AND ((storage.foldername(name))[1] = (auth.uid())::text)));



  create policy "Users can update their own private graphs"
  on "storage"."objects"
  as permissive
  for update
  to authenticated
using (((bucket_id = 'private_graphs'::text) AND ((storage.foldername(name))[1] = (auth.uid())::text)))
